 */
public class AiChainMdcFilter extends Filter<ILoggingEvent> {

    private String key = AiLogContext.AI_CHAIN;
    private String value = "true";

    @Override
    public FilterReply decide(ILoggingEvent event) {
        if (event == null || event.getMDCPropertyMap() == null) {
            return FilterReply.DENY;
        }
        String actual = event.getMDCPropertyMap().get(key);
        return value.equals(actual) ? FilterReply.ACCEPT : FilterReply.DENY;
    }

    public void setKey(String key) {
        this.key = key;
    }

    public void setValue(String value) {
        this.value = value;
    }
}

