package com.allthinkstars.framework.iot.ai.logging;

import ch.qos.logback.classic.spi.ILoggingEvent;
import ch.qos.logback.core.spi.FilterReply;
import org.junit.Assert;
import org.junit.Test;
import org.mockito.Mockito;

import java.util.Collections;
import java.util.HashMap;
import java.util.Map;

public class AiChainMdcFilterTest {

    @Test
    public void decide_shouldAcceptAiTaggedEvent() {
        AiChainMdcFilter filter = new AiChainMdcFilter();
        ILoggingEvent event = eventWithMdc(Collections.singletonMap(AiLogContext.AI_CHAIN, "true"));

        Assert.assertEquals(FilterReply.ACCEPT, filter.decide(event));
    }

    @Test
    public void decide_shouldDenyNonAiEvent() {
        AiChainMdcFilter filter = new AiChainMdcFilter();
        Map<String, String> mdc = new HashMap<>();
        mdc.put(AiLogContext.AI_CHAIN, "false");
        ILoggingEvent event = eventWithMdc(mdc);

        Assert.assertEquals(FilterReply.DENY, filter.decide(event));
        Assert.assertEquals(FilterReply.DENY, filter.decide(eventWithMdc(Collections.emptyMap())));
    }

    private ILoggingEvent eventWithMdc(Map<String, String> mdc) {
        ILoggingEvent event = Mockito.mock(ILoggingEvent.class);
        Mockito.when(event.getMDCPropertyMap()).thenReturn(mdc);
        return event;
    }
}

