    @Test
    public void dispatch_shouldNormalizeConversationIdAndMapCallerContext() {
        AiMcpToolsCallRequest req = buildRequest();
        req.setConversationId(" ");
        req.setToolCallId("call-1");
        req.setToolName("demo_tool");
        ObjectNode args = objectMapper.createObjectNode();
        args.put("query", "abc");
        req.setArgs(args);

        ObjectNode data = objectMapper.createObjectNode();
        data.put("result", "ok");
        when(toolRegistry.invoke(anyString(), any(), any(AiRunContext.class)))
            .thenReturn(ToolResult.ok("done", data));

        AiMcpToolsCallResponse resp = dispatcher.dispatch(req);

        Assert.assertEquals("mcp-call-1", resp.getConversationId());
        Assert.assertEquals("call-1", resp.getToolCallId());
        Assert.assertEquals("demo_tool", resp.getToolName());
        Assert.assertTrue(resp.isOk());
        Assert.assertNull(resp.getErrorCode());
        Assert.assertEquals("done", resp.getPreview());
        Assert.assertEquals("ok", resp.getData().path("result").asText());
        Assert.assertTrue(resp.getLatencyMs() >= 0);

        ArgumentCaptor<AiRunContext> ctxCaptor = ArgumentCaptor.forClass(AiRunContext.class);
        verify(toolRegistry).invoke(eq("demo_tool"), eq(args), ctxCaptor.capture());

        AiRunContext runContext = ctxCaptor.getValue();
        Assert.assertEquals(Long.valueOf(11L), runContext.getTenantId());
        Assert.assertEquals(Long.valueOf(22L), runContext.getSysUserId());
        Assert.assertEquals("22", runContext.getUserId());
        Assert.assertEquals(2, runContext.getVisibleDeviceInternalIds().size());
        Assert.assertEquals(1, runContext.getVisibleDeptIds().size());

        verify(contextResolverService).resolve(req.getContext());
    }

    @Test
    public void dispatch_shouldGenerateToolCallIdWhenMissing() {
        AiMcpToolsCallRequest req = buildRequest();
        req.setConversationId(null);
        req.setToolCallId(" ");
        req.setToolName("demo_tool");
        req.setArgs(null);

        when(toolRegistry.invoke(anyString(), any(), any(AiRunContext.class)))
            .thenReturn(ToolResult.ok("ok", objectMapper.createObjectNode()));

        AiMcpToolsCallResponse resp = dispatcher.dispatch(req);

        Assert.assertNotNull(resp.getToolCallId());
        Assert.assertFalse(resp.getToolCallId().isBlank());
        Assert.assertEquals("mcp-" + resp.getToolCallId(), resp.getConversationId());

        verify(toolRegistry).invoke(eq("demo_tool"), any(), any(AiRunContext.class));
    }

    @Test
    public void dispatch_shouldResolveRuntimeContextOnServer() {
        AiMcpToolsCallRequest req = buildRequest();
        req.setConversationId("conversation-x");
        req.setToolCallId("call-x");
