                Assert.assertEquals("call-x", MDC.get("aiToolCallId"));
                Assert.assertEquals("demo_tool", MDC.get("aiToolName"));
                Assert.assertEquals("11", MDC.get("aiTenantId"));
                Assert.assertEquals("22", MDC.get("aiUserId"));
                return ToolResult.ok("done", objectMapper.createObjectNode());
            });

        dispatcher.dispatch(req);

        Assert.assertNull(MDC.get("aiChain"));
        Assert.assertNull(MDC.get("aiConversationId"));
        Assert.assertNull(MDC.get("aiToolCallId"));
        Assert.assertNull(MDC.get("aiToolName"));
    }

    @Test
    public void dispatch_shouldConvertUnexpectedExceptionToErrorResponse() {
        AiMcpToolsCallRequest req = buildRequest();
        req.setConversationId("conversation-err");
        req.setToolCallId("call-err");
        req.setToolName("bad_tool");
        ObjectNode args = objectMapper.createObjectNode();
        args.put("k", "v");
        req.setArgs(args);

        when(toolRegistry.invoke(anyString(), any(), any(AiRunContext.class)))
            .thenThrow(new RuntimeException("boom"));

        AiMcpToolsCallResponse resp = dispatcher.dispatch(req);

        Assert.assertFalse(resp.isOk());
        Assert.assertEquals("tool_exec_unexpected", resp.getErrorCode());
        Assert.assertEquals("boom", resp.getMessage());
        Assert.assertEquals("boom", resp.getPreview());
        Assert.assertEquals("bad_tool", resp.getData().path("tool").asText());
        Assert.assertEquals("boom", resp.getData().path("error").asText());
        Assert.assertEquals("k", resp.getData().path("args").fieldNames().next());
    }

    @Test
    public void dispatch_shouldLogUnexpectedExceptionWithStackTraceAndInvocationIdentity() {
        AiMcpToolsCallRequest req = buildRequest();
        req.setConversationId("conversation-err");
        req.setToolCallId("call-err");
        req.setToolName("bad_tool");
        req.setArgs(objectMapper.createObjectNode());

        Logger logger = (Logger) LoggerFactory.getLogger(AiMcpToolDispatcher.class);
        ListAppender<ILoggingEvent> appender = new ListAppender<>();
        appender.start();
        logger.addAppender(appender);
        try {
            when(toolRegistry.invoke(anyString(), any(), any(AiRunContext.class)))
                .thenThrow(new RuntimeException("boom"));

            dispatcher.dispatch(req);

            Assert.assertEquals(1, appender.list.size());
            ILoggingEvent event = appender.list.get(0);
            Assert.assertTrue(event.getFormattedMessage().contains("conversationId=conversation-err"));
            Assert.assertTrue(event.getFormattedMessage().contains("toolCallId=call-err"));
            Assert.assertTrue(event.getFormattedMessage().contains("toolName=bad_tool"));
            Assert.assertNotNull(event.getThrowableProxy());
            Assert.assertEquals("true", event.getMDCPropertyMap().get("aiChain"));
            Assert.assertEquals("conversation-err", event.getMDCPropertyMap().get("aiConversationId"));
            Assert.assertEquals("call-err", event.getMDCPropertyMap().get("aiToolCallId"));
        } finally {
            logger.detachAppender(appender);
            appender.stop();
        }

    }

    private AiMcpToolsCallRequest buildRequest() {
