        resolved.setVisibleDeptIds(java.util.Collections.singletonList(11L));
        resolved.setCurrentFactory(factorySnapshot());
        resolved.setVisibleFurnaces(java.util.Collections.singletonList(furnaceSnapshot()));
        resolved.setPermissions(permissionSnapshot());
        when(contextResolverService.resolve(context)).thenReturn(resolved);
        return req;
    }

    private AiMcpCurrentFactorySnapshot factorySnapshot() {
        AiMcpCurrentFactorySnapshot snapshot = new AiMcpCurrentFactorySnapshot();
        snapshot.setDeptId(11L);
        snapshot.setDeptName("factory-a");
        return snapshot;
    }

    private AiMcpFurnaceSnapshot furnaceSnapshot() {
        AiMcpFurnaceSnapshot snapshot = new AiMcpFurnaceSnapshot();
        snapshot.setDeviceInternalId(201L);
        snapshot.setFnNo(0);
