import lombok.RequiredArgsConstructor;
import org.springframework.beans.factory.ListableBeanFactory;
import org.springframework.boot.context.properties.EnableConfigurationProperties;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;

import java.util.Map;

@Configuration
@EnableConfigurationProperties(AiProperties.class)
@RequiredArgsConstructor
public class AiAutoConfiguration {

    private ObjectMapper objectMapper = new ObjectMapper().findAndRegisterModules();


    @Bean
    public ToolRegistry aiToolRegistry(ListableBeanFactory beanFactory) {
        // 工具白名单注册点：所有模型发出的 tool_call 必须在 registry 中存在才会执行。
        // 自动发现所有 @AiToolComponent 工具类，避免在配置层手工维护工具列表。
        ToolRegistry registry = new ToolRegistry();
        Map<String, Object> toolBeans = beanFactory.getBeansWithAnnotation(AiToolComponent.class);
        toolBeans.entrySet().stream()
            .sorted(Map.Entry.comparingByKey())
            .forEach(e -> registry.registerAnnotatedBean(objectMapper, e.getValue()));
        return registry;
    }

    @Bean
    public AiContextResolveService aiMcpContextResolverService(IotCommonSupport iotCommonSupport,
                                                               SysDeptMapper sysDeptMapper,
                                                               UnifiedUserDeptService userDeptService,
                                                               TbDeviceFurnaceMapper tbDeviceFurnaceMapper) {
        return new AiContextResolveService(iotCommonSupport, userDeptService, sysDeptMapper, tbDeviceFurnaceMapper);
    }

    @Bean
    public AiMcpToolDispatcher aiMcpToolDispatcher(ToolRegistry registry,
                                                   AiContextResolveService contextResolverService) {
        // dispatcher 负责单次 tools/call 的执行编排与调用审计日志。
        return new AiMcpToolDispatcher(registry, objectMapper, contextResolverService);
