import com.allthinkstars.framework.iot.ai.tools.support.AiRunContext;
import com.fasterxml.jackson.databind.JsonNode;
import com.fasterxml.jackson.databind.ObjectMapper;
import lombok.RequiredArgsConstructor;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

@RequiredArgsConstructor
public class AiMcpToolDispatcher {

    private static final Logger LOG = LoggerFactory.getLogger(AiMcpToolDispatcher.class);
    private static final Logger INVOKE_LOG = LoggerFactory.getLogger("ai.tool.invoke");
    private static final int PREVIEW_MAX_CHARS = 512;

    private final ToolRegistry toolRegistry;
    private final ObjectMapper objectMapper;
    private final AiContextResolveService contextResolverService;

    /**
     * tools/call 实际调度：
     * 1) 标准化 callId/conversationId，避免上游漏传导致链路不可追踪。
     * 2) 基于最小 caller 信息在服务端统一 resolve 运行时上下文。
     * 3) 执行工具并统一映射返回结构。
     * 4) 记录工具调用审计日志。
     */
    public AiMcpToolsCallResponse dispatch(AiMcpToolsCallRequest req) {
        JsonNode args = req.getArgs() == null ? objectMapper.createObjectNode() : req.getArgs();
        String callId = normalizeCallId(req.getToolCallId());
        String conversationId = normalizeConversationId(req.getConversationId(), callId);
        long startMs = System.currentTimeMillis();

        ToolResult result;
        try (AiLogContext ignored = AiLogContext.openToolCall(
            conversationId,
            callId,
            req.getToolName(),
            safeTenant(req.getContext()),
            safeUser(req.getContext())
        )) {
            try {
                result = toolRegistry.invoke(req.getToolName(), args, buildRunContext(req.getContext()));
            } catch (Exception e) {
                logUnexpectedError(conversationId, callId, req.getToolName(), e);
                result = unexpectedError(req.getToolName(), args, e);
            }
        }

        long latencyMs = System.currentTimeMillis() - startMs;
        String status = result.isOk() ? "ok" : "error";
        String errorCode = result.isOk() ? "-" : safeCode(result.getCode());
        logInvoke(
            conversationId,
            callId,
            req.getToolName(),
            safeTenant(req.getContext()),
            safeUser(req.getContext()),
            args,
            status,
            latencyMs,
            errorCode,
            result.getPreview()
        );

        AiMcpToolsCallResponse resp = new AiMcpToolsCallResponse();
        resp.setConversationId(conversationId);
        resp.setToolCallId(callId);
        resp.setToolName(req.getToolName());
        resp.setOk(result.isOk());
        resp.setErrorCode(result.isOk() ? null : safeCode(result.getCode()));
        resp.setMessage(result.getMessage());
        resp.setPreview(result.getPreview());
        resp.setData(result.getData());
        resp.setLatencyMs(latencyMs);
        return resp;
    }

    /**
     * 将 MCP caller 上下文转换为工具运行时上下文。
     * 工具执行所需范围信息统一由服务端 resolve，避免 Python 侧重复拼装上下文。
     */
    private AiRunContext buildRunContext(AiMcpCallerContext caller) {
        AiRunContext ctx = new AiRunContext();
        if (caller != null) {
            ctx.setSysUserId(caller.getUserId());
            if (caller.getUserId() != null) {
                ctx.setUserId(String.valueOf(caller.getUserId()));
            }
            AiMcpContextResolveResponse resolved = contextResolverService.resolve(caller);
            ctx.setTenantId(resolved.getTenantDeptId());
            ctx.setVisibleDeviceInternalIds(resolved.getVisibleDeviceInternalIds());
            ctx.setVisibleDeptIds(resolved.getVisibleDeptIds());
        }
        return ctx;
    }

    /**
     * 兜底异常统一转成 ToolResult，避免异常泄漏导致调用方协议不一致。
