    private ToolResult unexpectedError(String toolName, JsonNode args, Exception e) {
        String msg = e.getMessage() == null ? e.toString() : e.getMessage();
        var data = objectMapper.createObjectNode();
        data.put("tool", toolName);
        data.set("args", args);
        data.put("error", msg);
        return ToolResult.fail("tool_exec_unexpected", msg, data);
    }

    private void logUnexpectedError(String conversationId, String toolCallId, String toolName, Exception e) {
        LOG.error(
            "AI tool execution failed conversationId={} toolCallId={} toolName={}",
            safe(conversationId),
            safe(toolCallId),
            safe(toolName),
            e
        );
    }

    private String safeTenant(AiMcpCallerContext ctx) {
        return ctx == null ? null : ctx.getTenantId();
    }

    private Long safeUser(AiMcpCallerContext ctx) {
        return ctx == null ? null : ctx.getUserId();
    }

    private String safeCode(String code) {
        return code == null || code.isBlank() ? "tool_error" : code;
    }

    private String normalizeConversationId(String conversationId, String callId) {
        if (conversationId != null && !conversationId.isBlank()) {
            return conversationId;
        }
        return "mcp-" + callId;
    }

    private String normalizeCallId(String toolCallId) {
        if (toolCallId != null && !toolCallId.isBlank()) {
            return toolCallId;
        }
        return java.util.UUID.randomUUID().toString();
    }

    private void logInvoke(String conversationId,
                           String toolCallId,
