    /**
     * 扫描并注册注解式工具方法。
     * 注册时会一次性构建：
     * - 可执行方法描述(ToolMethod)
     * - 对外暴露的工具元信息(ToolSpec)
     */
    public void registerAnnotatedBean(ObjectMapper objectMapper, Object toolBean) {
        if (toolBean == null || objectMapper == null) {
            return;
        }
        for (Method method : toolBean.getClass().getDeclaredMethods()) {
            AiToolDef toolDef = method.getAnnotation(AiToolDef.class);
            if (toolDef == null) {
                continue;
            }
            ToolMethod toolMethod = ToolMethod.of(objectMapper, toolBean, method, toolDef);
            String toolName = toolMethod.spec().getName();
            // 同名后注册会覆盖前者，作为显式白名单更新机制。
            methods.put(toolName, toolMethod.withSpec(toolMethod.spec().copy()));
            specs.put(toolName, toolMethod.spec().copy());
        }
    }

    /**
     * 工具统一调用入口，负责将异常归一为稳定错误码。
     */
    public ToolResult invoke(String toolName, JsonNode args, AiRunContext ctx) {
        ToolMethod method = methods.get(toolName);
        if (method == null) {
            return ToolResult.fail("tool_not_allowed", "工具不在白名单: " + toolName);
        }
        try {
            return method.invoke(args, ctx);
        } catch (IllegalArgumentException e) {
            String msg = e.getMessage() == null ? e.toString() : e.getMessage();
            if (msg.startsWith("缺少必填参数:")) {
                String missing = msg.substring("缺少必填参数:".length()).trim();
                return ToolResult.fail("tool_args_missing", msg, method.missingArgData(args, missing));
            }
            return ToolResult.fail("tool_args_invalid", msg, method.invalidArgData(args));
        } catch (Exception e) {
            String msg = e.getMessage() == null ? e.toString() : e.getMessage();
            return ToolResult.fail("tool_exec_error", msg, method.execErrorData(args, msg));
        }
    }

