    private static final class ToolMethod {
        private final ObjectMapper objectMapper;
        private final Object target;
        private final Method method;
        private final ToolSpec spec;
        private final List<ParameterBinding> bindings;
        private final Set<String> exposedParamNames;

        private ToolMethod(ObjectMapper objectMapper,
                           Object target,
                           Method method,
                           ToolSpec spec,
                           List<ParameterBinding> bindings) {
            this.objectMapper = objectMapper;
            this.target = target;
            this.method = method;
            this.spec = spec;
            this.bindings = bindings;
            this.exposedParamNames = buildExposedParamNames(bindings);
            this.method.setAccessible(true);
        }

        static ToolMethod of(ObjectMapper objectMapper, Object target, Method method, AiToolDef toolDef) {
            String toolName = toolDef.name() == null || toolDef.name().isBlank()
                ? method.getName()
                : toolDef.name().trim();
            List<ParameterBinding> bindings = new ArrayList<>();
            List<ToolParamSpec> params = new ArrayList<>();
            for (Parameter parameter : method.getParameters()) {
                if (AiRunContext.class.isAssignableFrom(parameter.getType())) {
                    bindings.add(ParameterBinding.context(parameter.getType()));
                    continue;
                }
                AiToolParam toolParam = parameter.getAnnotation(AiToolParam.class);
                String paramName = resolveParamName(parameter, toolParam);
                boolean required = parameter.getType().isPrimitive() || (toolParam != null && toolParam.required());
                String description = toolParam == null ? "" : toolParam.value();
                String title = toolParam == null || toolParam.title() == null || toolParam.title().isBlank()
                    ? ""
                    : toolParam.title().trim();
                List<String> examples = buildExamples(toolParam);
                params.add(new ToolParamSpec(paramName, inferJsonType(parameter.getType()), required, description, title, examples));
                bindings.add(ParameterBinding.exposed(paramName, parameter.getParameterizedType(), required));
            }
            ToolSpec spec = new ToolSpec(toolName, toolDef.value(), params);
            return new ToolMethod(objectMapper, target, method, spec, bindings);
        }

        private static List<String> buildExamples(AiToolParam toolParam) {
            List<String> examples = new ArrayList<>();
            if (toolParam == null) {
                return examples;
            }
            return Arrays.stream(toolParam.examples() == null ? new String[0] : toolParam.examples())
                .filter(Objects::nonNull)
                .map(String::trim)
                .filter(s -> !s.isEmpty())
                .collect(java.util.stream.Collectors.toList());
        }

        ToolMethod withSpec(ToolSpec newSpec) {
            return new ToolMethod(objectMapper, target, method, newSpec, bindings);
        }

        ToolSpec spec() {
            return spec;
        }

        ToolResult invoke(JsonNode jsonArgs, AiRunContext ctx) throws Exception {
            JsonNode args = jsonArgs == null || jsonArgs.isNull() ? objectMapper.createObjectNode() : jsonArgs;
            // 先拦截未知字段，避免模型 hallucination 参数进入业务方法。
            validateUnknownFields(args);
            Object[] argv = bindArgs(args, ctx);
            Object out = method.invoke(target, argv);
            if (out instanceof ToolResult) {
                return (ToolResult) out;
            }
            if (out == null) {
                return ToolResult.ok("", objectMapper.createObjectNode());
            }
            if (out instanceof String) {
                return ToolResult.ok((String) out, objectMapper.createObjectNode());
            }
            return ToolResult.ok(out.toString(), objectMapper.valueToTree(out));
        }

        JsonNode missingArgData(JsonNode args, String missingField) {
            return objectMapper.createObjectNode()
                .put("tool", spec.getName())
                .put("missingField", missingField)
                .set("args", args == null ? objectMapper.createObjectNode() : args);
        }

        JsonNode invalidArgData(JsonNode args) {
            return objectMapper.createObjectNode()
                .put("tool", spec.getName())
                .set("args", args == null ? objectMapper.createObjectNode() : args);
        }

        JsonNode execErrorData(JsonNode args, String error) {
            ObjectNode node = objectMapper.createObjectNode();
            node.put("tool", spec.getName());
            node.set("args", args == null ? objectMapper.createObjectNode() : args);
            node.put("error", error);
            return node;
        }

        private void validateUnknownFields(JsonNode args) {
            if (args == null || !args.isObject()) {
                return;
            }
            Iterator<String> it = args.fieldNames();
            while (it.hasNext()) {
                String field = it.next();
                if (!exposedParamNames.contains(field)) {
                    throw new IllegalArgumentException("未知参数: " + field);
                }
            }
        }

        private Object[] bindArgs(JsonNode args, AiRunContext ctx) {
            Object[] argv = new Object[bindings.size()];
            for (int i = 0; i < bindings.size(); i++) {
                ParameterBinding binding = bindings.get(i);
                if (binding.contextParam) {
                    // 上下文参数不对外暴露，由 runtime 注入。
                    argv[i] = ctx;
                    continue;
                }
                JsonNode value = args.get(binding.name);
                if (value == null || value.isNull()) {
                    if (binding.required) {
                        throw new IllegalArgumentException("缺少必填参数: " + binding.name);
                    }
                    argv[i] = null;
                    continue;
                }
                try {
                    if (JsonNode.class.isAssignableFrom(binding.rawType())) {
                        argv[i] = value;
                    } else {
                        argv[i] = objectMapper.treeToValue(value, objectMapper.constructType(binding.type));
                    }
                } catch (Exception e) {
                    throw new IllegalArgumentException("参数类型不匹配: " + binding.name);
                }
            }
            return argv;
        }

        private static String resolveParamName(Parameter parameter, AiToolParam toolParam) {
            if (toolParam != null && toolParam.name() != null && !toolParam.name().isBlank()) {
                return toolParam.name().trim();
            }
            return parameter.getName();
        }

        private static Set<String> buildExposedParamNames(List<ParameterBinding> bindings) {
            Set<String> names = new LinkedHashSet<>();
            for (ParameterBinding binding : bindings) {
                if (!binding.contextParam) {
                    names.add(binding.name);
                }
            }
            return names;
        }
    }

    private static final class ParameterBinding {
        private final String name;
        private final java.lang.reflect.Type type;
        private final boolean required;
        private final boolean contextParam;

        private ParameterBinding(String name, java.lang.reflect.Type type, boolean required, boolean contextParam) {
            this.name = name;
            this.type = type;
            this.required = required;
            this.contextParam = contextParam;
        }

        static ParameterBinding exposed(String name, java.lang.reflect.Type type, boolean required) {
            return new ParameterBinding(name, type, required, false);
        }

        static ParameterBinding context(java.lang.reflect.Type type) {
            return new ParameterBinding("_ctx_", type, false, true);
        }

        Class<?> rawType() {
            return type instanceof Class<?> ? (Class<?>) type : Object.class;
        }
    }
