package com.allthinkstars.framework.iot.app.service.ai;

import cn.dev33.satoken.session.SaSession;
import cn.dev33.satoken.stp.StpUtil;
import com.allthinkstars.framework.iot.ai.config.AiProperties;
import com.allthinkstars.framework.iot.nextg.service.UnifiedUserDeptService;
import com.ruoyi.common.constant.CacheConstants;
import com.ruoyi.common.core.domain.model.LoginUser;
import com.ruoyi.common.helper.LoginHelper;
import lombok.RequiredArgsConstructor;
import org.apache.commons.lang3.StringUtils;
import org.springframework.http.HttpHeaders;
import org.springframework.http.HttpStatus;
import org.springframework.stereotype.Service;
import org.springframework.web.server.ResponseStatusException;

import javax.servlet.http.HttpServletRequest;
import java.util.Objects;
import java.util.UUID;

@Service
@RequiredArgsConstructor
public class AiGatewayAuthService {

    private static final String HEADER_TRACE_ID = "X-Trace-Id";

    private final UnifiedUserDeptService unifiedUserDeptService;

    public AiGatewayProxyService.BizPrincipal resolvePrincipal(HttpServletRequest request, AiProperties.Gateway gateway) {
        if (!gateway.isEnabled()) {
            throw new ResponseStatusException(HttpStatus.FORBIDDEN, "ai gateway disabled");
        }

        String traceId = resolveTraceId(request);
        String authorization = request == null ? null : request.getHeader(HttpHeaders.AUTHORIZATION);
        if (StringUtils.isNotBlank(authorization)) {
            return resolvePrincipalByAuthorization(authorization, traceId);
        }

        Long userId = null;
        Long deptId = null;
        try {
            userId = LoginHelper.getUserId();
            deptId = LoginHelper.getDeptId();
        } catch (Exception ignored) { // NOSONAR
            // ignore and continue with anonymous debug fallback
        }
        if (userId != null && deptId != null) {
            return buildPrincipal(userId, deptId, traceId);
        }

        if (gateway.isAllowAnonymousDebug()
            && StringUtils.isNotBlank(gateway.getDefaultUserId())
            && StringUtils.isNotBlank(gateway.getDefaultTenantDeptId())) {
            return new AiGatewayProxyService.BizPrincipal(
                gateway.getDefaultUserId().trim(),
                gateway.getDefaultTenantDeptId().trim(),
                traceId
            );
        }

        throw new ResponseStatusException(HttpStatus.UNAUTHORIZED, "unauthenticated");
    }

    private AiGatewayProxyService.BizPrincipal resolvePrincipalByAuthorization(String authorization, String traceId) {
        String tokenValue = extractBearerToken(authorization);
        if (StringUtils.isBlank(tokenValue)) {
            throw new ResponseStatusException(HttpStatus.UNAUTHORIZED, "invalid authorization token");
        }

        try {
            LoginUser loginUser = resolveLoginUserByToken(tokenValue);
            if (loginUser == null || loginUser.getUserId() == null) {
                throw new ResponseStatusException(HttpStatus.UNAUTHORIZED, "login session expired");
            }

            // 将 token 对应的登录态绑定到当前线程，便于 UnifiedUserDeptService 复用现有 app 登录上下文逻辑。
            bindLoginContext(tokenValue, loginUser);

            Long userId = loginUser.getUserId();
            Long deptId = unifiedUserDeptService.getDeptId(userId);
            if (deptId == null) {
                throw new ResponseStatusException(HttpStatus.UNAUTHORIZED, "dept context unavailable");
            }
            return buildPrincipal(userId, deptId, traceId);
        } catch (ResponseStatusException ex) {
            throw ex;
        } catch (Exception ex) { // NOSONAR
            throw new ResponseStatusException(HttpStatus.UNAUTHORIZED, "invalid authorization token", ex);
        }
    }

    private AiGatewayProxyService.BizPrincipal buildPrincipal(Long userId, Long deptId, String traceId) {
        return new AiGatewayProxyService.BizPrincipal(
            String.valueOf(Objects.requireNonNull(userId)),
            String.valueOf(Objects.requireNonNull(deptId)),
            traceId
        );
    }

    LoginUser resolveLoginUserByToken(String tokenValue) {
        SaSession tokenSession = StpUtil.getTokenSessionByToken(tokenValue);
        return tokenSession == null ? null : (LoginUser) tokenSession.get(LoginHelper.LOGIN_USER_KEY);
    }

    void bindLoginContext(String tokenValue, LoginUser loginUser) {
        StpUtil.setTokenValue(tokenValue);
        cn.dev33.satoken.context.SaHolder.getStorage().set(LoginHelper.LOGIN_USER_KEY, loginUser);
    }

    private String resolveTraceId(HttpServletRequest request) {
        String traceId = request == null ? null : request.getHeader(HEADER_TRACE_ID);
        if (StringUtils.isBlank(traceId)) {
            return UUID.randomUUID().toString().replace("-", "");
        }
        return traceId.trim();
    }

    private String extractBearerToken(String authorization) {
        if (StringUtils.isBlank(authorization)) {
            return null;
        }
        String value = authorization.trim();
        if (StringUtils.startsWithIgnoreCase(value, CacheConstants.TOKEN_PREFIX)) {
            return StringUtils.trimToNull(value.substring(CacheConstants.TOKEN_PREFIX.length()));
        }
        return StringUtils.trimToNull(value);
    }
}
